(function () {
  var SEARCH_INDEX = [{"file":"sutrakritang-ch1.html","num":"Ch 1","title":"Ch 1 — The Doctrine (Samayaktha)","sutras":[{"id":"hero","num":"Ch 1","title":"The Doctrine (Samayaktha) — On true doctrine versus false doctrine — the foundation of liberation"},{"id":"sutra-1","num":"1.1","title":"Let the wise one attain understanding and know the nature of bondage fully — what does the Hero call bondage, and what single truth, when known, break"},{"id":"sutra-2","num":"1.2","title":"One who possesses conscious beings or unconscious things — even the least trifle — or who approves of others possessing them, is not freed from suffer"},{"id":"sutra-3","num":"1.3","title":"One who himself kills living beings, or causes others to kill them, or approves of the killing, increases enmity toward himself."},{"id":"sutra-4","num":"1.4","title":"The ignorant one is afflicted by attachment to those in whose family he is born and among whom he lives — deeply ensnared in mutual craving."},{"id":"sutra-5","num":"1.5","title":"Wealth and kinsmen — all of this — do not protect one; knowing life to be brief, the wise one breaks free from karma."},{"id":"sutra-6","num":"1.6","title":"Some ascetics and priests, having abandoned one set of entanglements, are still deeply addicted to pleasures — attached and deluded in their own doctr"},{"id":"sutra-7","num":"1.7","title":"Earth, water, fire, air, vegetation, and mobile beings — some say these are both souls and non-souls."},{"id":"sutra-8","num":"1.8","title":"Earth, water, fire, air, vegetation, and mobile beings — these are all souls, say some; but this everything-is-soul view is not recognized by the know"},{"id":"sutra-9","num":"1.9","title":"Living beings exist in their specific forms, and one should know their diversity — but the view that the soul and the body are one thing is also not r"},{"id":"sutra-10","num":"1.10","title":"Those who teach non-action — who say there is no moral consequence to action — regarding soul and non-soul: they are lost in both realms and experienc"},{"id":"sutra-11","num":"1.11","title":"Some souls do not become freed; those who are freed do not return — knowing this path, knowing this doctrine, is what the knower of the path recognize"},{"id":"sutra-12","num":"1.12","title":"Some say there is no other world, \"do nothing\" — they destroy even themselves, for wrong-viewing persons exist in delusion."},{"id":"sutra-13","num":"1.13","title":"There is nowhere no soul — thus mobile beings are freed; there is no such thing as non-existence — thus know, O wise one."},{"id":"sutra-14","num":"1.14","title":"When turned aside from the path, the resolute one should draw himself back — attending to himself alone — and among all people speaking in the world, "},{"id":"sutra-15","num":"1.15","title":"Now even one who considers himself learned — \"I have seen the soul before\" — pierced by sharp thorns of passion, does not attain happiness as stated."},{"id":"sutra-16","num":"1.16","title":"Having seen the fear of the cycle of births and knowing suffering, one who is drawn aside should pull back — and should cease from all harm-causing ac"},{"id":"sutra-17","num":"1.17","title":"Whatever doctrines exist in the world — for none of them does the path of non-action exist; those men are bound by those very karmas, having been turn"},{"id":"sutra-18","num":"1.18","title":"All living beings, all beings with life-force, all souls, all sentient creatures — they should not be killed, should not be commanded to be killed, sh"},{"id":"sutra-19","num":"1.19","title":"This is the doctrine — permanent, certain, eternal, spoken by the Conquerors — knowing this fully, the wise one, the thoughtful one, should not be neg"},{"id":"sutra-20","num":"1.20","title":"One is well-established in this world but not established in the other world — right understanding is indeed difficult to attain; do not be negligent "},{"id":"sutra-21","num":"1.21","title":"⚠️ The soul, without beginning and without known origin, has wandered many times through the cycle of birth and death, taking on bodies, born from var"},{"id":"sutra-22","num":"1.22","title":"Having wandered for many lifetimes, the soul — enduring the torments of the womb, illness, and disease — again and again undergoes birth, old age, and"},{"id":"sutra-23","num":"1.23","title":"⚠️ Those who speak of a path of purification — they have not attained the teaching of the Knower; for they have not fully understood the root of karma"},{"id":"sutra-24","num":"1.24","title":"Some ascetics and brahmins, tightly bound, who rejoice in the world and in what comes after — they only go around in the cycle of birth and death; thu"},{"id":"sutra-25","num":"1.25","title":"One who does not harm any living being — knowing, restrained, composed — shaking off karma, free of delusion, with no remaining karma, is known as a C"},{"id":"sutra-26","num":"1.26","title":"Whoever knows the confusion in the world, who has crossed over and has abandoned the three realms of existence, who stands on the path and is at peace"},{"id":"sutra-27","num":"1.27","title":"Now the wise one — fulfilled, devoted to pure sustenance — at peace, wandering as a renunciant, composed, abandons all possessions."},{"id":"sutra-28","num":"1.28","title":"Those fatalists — those who teach fate — say that through personal effort nothing can be achieved; they have not attained the teaching of the Knower."},{"id":"sutra-29","num":"1.29","title":"Fatalists are indeed unwise, entered into delusion and karma — but those who experience the fruit of pure karma do so through their own effort."},{"id":"sutra-30","num":"1.30","title":"All living beings, all creatures — knowing both benefit and suffering — wander in the cycle of births through birth, old age, and death."},{"id":"sutra-31","num":"1.31","title":"Whoever knows this doctrine — the resolute one, the wise one, who has seen clearly — should not perform harmful karma, and should not approve of it ei"},{"id":"sutra-32","num":"1.32","title":"The ignorant do not know this highest truth — they do not know liberation from suffering; thus says one who has mastered the world — for such a one th"},{"id":"sutra-33","num":"1.33","title":"The ignorant, the wrong-viewing, those who praise themselves and are laden with karma — those who do not know this doctrine go to a state of suffering"},{"id":"sutra-34","num":"1.34","title":"Whoever is ignorant and without right understanding, joined with wrong perception — know certainly that this is bondage; the pure soul is freed from k"},{"id":"sutra-35","num":"1.35","title":"⚠️ Such is the view of those who perform harmful karma — one who has deviated and has fallen into confusion — even that teaching has not attained the "},{"id":"sutra-36","num":"1.36","title":"Let not the restrained one go toward sensual indulgence, and let him not take what is not given — let him not engage in harmful enterprise; this is th"},{"id":"sutra-37","num":"1.37","title":"The monk who fears suffering, who maintains restraint, who has cut through attachment and aversion — let him practice the discipline of the path."},{"id":"sutra-38","num":"1.38","title":"There are many great teachers in the world, speakers of wisdom — they praise each other, but my truth is not known by them."},{"id":"sutra-39","num":"1.39","title":"Having abandoned in all ways the entanglement with the world, the sage, established in restraint, attends to himself alone."},{"id":"sutra-40","num":"1.40","title":"This is the path to be followed by one who knows this doctrine — he is not afraid, not agitated, not negligent even in minor matters."},{"id":"sutra-41","num":"1.41","title":"The great sage, cautious of what is born of ignorance, who has crossed over all suffering — one who knows the world, this single knower."},{"id":"sutra-42","num":"1.42","title":"Even struck by the axle-pin (deeply wounded), he is resolute — that great sage, attending to himself, steadfast, is described as one who has understoo"},{"id":"sutra-43","num":"1.43","title":"He is neither hopeful nor despairing, neither elated nor lamenting in sorrow — in complete suffering and in complete happiness alike, standing in equa"},{"id":"sutra-44","num":"1.44","title":"In gain and in loss alike — he is detached, freed — in activity not bound to outcomes; this is the path, the highest."},{"id":"sutra-45","num":"1.45","title":"Thus, knowing even a little, he is detached and freed — on the highest path to liberation, as declared by the Conqueror for the future."},{"id":"sutra-46","num":"1.46","title":"The ignorant, unwise one acts, thinking the entire world is just this — but one who has fully understood everything, for him there is no suffering: th"},{"id":"sutra-47","num":"1.47","title":"Thus right knowledge and right perception and right conduct together — having attained the words of the Conqueror, this is the path declared by the Co"},{"id":"sutra-48","num":"1.48","title":"Having fully understood true knowledge — what bondage is and what liberation is — that monk, restrained and well-composed, avoids food obtained throug"},{"id":"sutra-49","num":"1.49","title":"This is the conduct-doctrine taught by the Conquerors — one should ask about it and not destroy it, having attained the teaching of the Conquerors."},{"id":"sutra-50","num":"1.50","title":"Let him not be intoxicated, let him not harm, let him not speak falsehood — let him not injure living beings, let him not perform any harmful karma wh"},{"id":"sutra-51","num":"1.51","title":"Thus understanding the world, having recognized all states of being — one who is restrained from all harmful enterprise: for him there is no fear anyw"},{"id":"sutra-52","num":"1.52","title":"Thus endowed with right conduct, composed in right knowledge and right perception — know that one as wise: this is the path, thus it has been declared"},{"id":"sutra-53","num":"1.53","title":"Let him not cut, not split, not burn — having abandoned what brings little benefit; all souls should be known, and knowing them, let him not initiate "},{"id":"sutra-54","num":"1.54","title":"This has been declared as the path of discipline — or declared partially in the teaching of the Knower; truly he is the Knower, the speaker of truth —"},{"id":"sutra-55","num":"1.55","title":"Now even the wise one — having known suffering in all its forms, having fully understood it, composed — this is the highest path."},{"id":"sutra-56","num":"1.56","title":"The enlightened one should enlighten others — and not again set intentions in motion; thus right knowledge and right perception: this is the highest p"},{"id":"sutra-57","num":"1.57","title":"This indeed is the essence of the world, taught by the Tirthankara — just as the sensual one craves benefit, so in this world this is the essence."},{"id":"sutra-58","num":"1.58","title":"The fully enlightened one — skilled, resolute, thoroughly restrained, having understood — should not indulge in sense pleasures, which are impermanent"},{"id":"sutra-59","num":"1.59","title":"Having understood, let the monk move through the world, practicing the silence of the sage — those who are disciplined and well-composed attain libera"},{"id":"sutra-60","num":"1.60","title":"The unwise ones, craving what has no real purpose, wander in the cycle — beginninglessly in the ocean of suffering, they do not cross the ocean of exi"},{"id":"sutra-61","num":"1.61","title":"The monk who has understood what appropriate food is — purely restrained, free from food-causing harm — such a monk does not consume what violates thi"},{"id":"sutra-62","num":"1.62","title":"Food produced through harm-causing activity, and food that is not worthy of seeking — the monk, having abandoned that, is on the highest path to liber"},{"id":"sutra-63","num":"1.63","title":"⚠️ As stated in the teaching regarding food prepared for guests, in the householder's family — that monk, avoiding even such incidental food, is truly"},{"id":"sutra-64","num":"1.64","title":"Those in the world who teach that everything is done by a Creator — by knowing (their view of) the Creator of the world, how can such a one be freed f"},{"id":"sutra-65","num":"1.65","title":"See the world from the world's own root — what God, and what would he do? Having conceived of divine perfection, one must work out one's own liberatio"},{"id":"sutra-66","num":"1.66","title":"Some declare the entire world to be permanent by nature; others declare the world to be impermanent by nature — neither of these two has attained the "},{"id":"sutra-67","num":"1.67","title":"The world is both permanent and impermanent — thus the Conquerors declared previously — just as a tree is permanent in its wood but impermanent in its"},{"id":"sutra-68","num":"1.68","title":"Some say liberation is eternal — some say liberation does not exist — both of these two do not know the truth."},{"id":"sutra-69","num":"1.69","title":"⚠️ Some say there is a soul-connection — some say there is no connection without attachment; some say souls are non-doers — both of these do not know."},{"id":"sutra-70","num":"1.70","title":"⚠️ Some say the soul transforms — some say it does not transform; some say one's own karma alone determines — both of these do not know."},{"id":"sutra-71","num":"1.71","title":"Some say the soul is dependent on something — that same soul possesses knowledge and other qualities; some say the soul is independent — both of these"},{"id":"sutra-72","num":"1.72","title":"Some say the soul exists — some say the soul does not exist — some say it is inexpressible — both or all of any two of these, held as absolute, do not"},{"id":"sutra-73","num":"1.73","title":"Some say the soul is eternal — some say the soul is non-eternal — some say it is both eternal and non-eternal — all of these as absolute claims do not"},{"id":"sutra-74","num":"1.74","title":"All of these — all such people — seized by wrong perception, thereby attain further wrong understanding, and all of them end up in states of suffering"},{"id":"sutra-75","num":"1.75","title":"Those who are transformed by these wrong views, who are shaped by wrong orientation — they do not know liberation from suffering; this is the path, th"},{"id":"sutra-76","num":"1.76","title":"Above, below, and sideways — in all directions — mobile and immobile beings should not be harmed, should not be killed; this is the doctrine, purified"},{"id":"sutra-77","num":"1.77","title":"For all living beings, all creatures, all souls, all sentient ones — some speak of them as divine — the monk should wander without causing any sufferi"},{"id":"sutra-78","num":"1.78","title":"Whether toward others or toward himself — established, restrained, steady — the wise one has understanding of the cycle of all beings, toward all bein"},{"id":"sutra-79","num":"1.79","title":"Moving about with wisdom, the monk — purely restrained — should never enter into conflict, the monk should practice the discipline of the path."},{"id":"sutra-80","num":"1.80","title":"Let not the monk practice the rod, let him not act like a householder's man — with folded hands in reverence, the monk should wander."},{"id":"sutra-81","num":"1.81","title":"The monk who has truly renounced does not eat even what is bitter or pungent — restrained with a disposition of gentleness; this is the highest path."},{"id":"sutra-82","num":"1.82","title":"Possessing nothing, unattached, pure, with doubts shaken off — self-guarded, always vigilant — this is the doctrine, well-established."},{"id":"sutra-83","num":"1.83","title":"The monk who is restrained in all things, free of delusion in all things, who has crossed over all suffering — this is the highest path."},{"id":"sutra-84","num":"1.84","title":"Without craving, without desire for what is pleasing, and without attachment to the delightful body — established on the path of discipline, the monk "},{"id":"sutra-85","num":"1.85","title":"The monk who is like that — with senses conquered, with mind conquered, having shaken off harmful karma — is never bound again."},{"id":"sutra-86","num":"1.86","title":"Thus, composed in accordance with the teaching, with delusion completely removed, having crossed over all suffering — one attains liberation."},{"id":"sutra-87","num":"1.87","title":"This indeed is the essence of the world — this is the doctrine declared by the Conqueror — this is the highest path — this is the truth, eternal."},{"id":"sutra-88","num":"1.88","title":"This is the doctrine — permanent, certain — by the authority of the Arihantas; know this Samaya (true doctrine) — thus I say."}]},{"file":"sutrakritang-ch2.html","num":"Ch 2","title":"Ch 2 — Sensation (Vasudevahindi)","sutras":[{"id":"hero","num":"Ch 2","title":"Sensation (Vasudevahindi) — Karma ripens into experience. The wise one endures it all with equanimity."},{"id":"sutra-1","num":"2.1","title":"Whatever sufferings exist in the world — all of them arise from karma."},{"id":"sutra-2","num":"2.2","title":"Whatever pleasures exist in the world — they too arise from karma."},{"id":"sutra-3","num":"2.3","title":"Therefore the wise one who has crossed to the other shore understands sensation."},{"id":"sutra-4","num":"2.4","title":"Whether it is pleasure or pain, the learned one should endure it."},{"id":"sutra-5","num":"2.5","title":"Just as a man afflicted by disease is treated by a skilled physician — so too the soul afflicted by karma is treated by understanding."},{"id":"sutra-6","num":"2.6","title":"He knows the root of suffering; he knows karma as bondage."},{"id":"sutra-7","num":"2.7","title":"He does not grieve nor does he rejoice — he sees a lump of clay and a lump of gold as equal."},{"id":"sutra-8","num":"2.8","title":"In the body — a framework of bone, flesh, and skin — there is no ownership."},{"id":"sutra-9","num":"2.9","title":"One who has conquered the senses is not overwhelmed by sensation."},{"id":"sutra-10","num":"2.10","title":"Just as fire burns away wood — so too does the monk burn away his karma."},{"id":"sutra-11","num":"2.11","title":"For one who is immersed in practice, there is no fear of suffering; sensation does not disturb him."},{"id":"sutra-12","num":"2.12","title":"Overpowered by hardship, he does not seek escape into comfort."},{"id":"sutra-13","num":"2.13","title":"He does not become angry nor does he become pleased — he lives with pleasure and pain treated equally."},{"id":"sutra-14","num":"2.14","title":"In taking food without heedlessness, bondage does not arise for him."},{"id":"sutra-15","num":"2.15","title":"No living beings should be harmed; this is what the Lord declared."},{"id":"sutra-16","num":"2.16","title":"The one who is truly wise remains in equanimity, enduring suffering without agitation."},{"id":"sutra-17","num":"2.17","title":"Whatever is pleasant and whatever is unpleasant — both are the fruits of karma."},{"id":"sutra-18","num":"2.18","title":"The steadfast one is not rash — he stands established in endurance."},{"id":"sutra-19","num":"2.19","title":"The one who truly knows sensation has reached the shore of liberation."},{"id":"sutra-20","num":"2.20","title":"For one whose sensation-karma has been exhausted, it does not arise again."},{"id":"sutra-21","num":"2.21","title":"The wise one restrains himself and cultivates purity of being."},{"id":"sutra-22","num":"2.22","title":"Neither fear nor anxiety, neither attachment nor despair — he lives beyond these."},{"id":"sutra-23","num":"2.23","title":"The monk who has fully understood does not accumulate karma."},{"id":"sutra-24","num":"2.24","title":"This is declared to be the path to liberation from all suffering."},{"id":"sutra-25","num":"2.25","title":"Thus, having understood the chapter on sensation, one knows all things fully. — iti bemi"}]},{"file":"sutrakritang-ch3.html","num":"Ch 3","title":"Ch 3 — Consciousness (Chatushparisha)","sutras":[{"id":"hero","num":"Ch 3","title":"Consciousness (Chatushparisha) — The soul that knows is different from the matter it knows."},{"id":"sutra-1","num":"3.1","title":"Having understood what is conscious and having understood what is unconscious — one is freed."},{"id":"sutra-2","num":"3.2","title":"That which is the soul is not the non-soul — this knowledge does not reside in the ignorant."},{"id":"sutra-3","num":"3.3","title":"The soul is mingled with non-soul — the knowing one distinguishes them."},{"id":"sutra-4","num":"3.4","title":"The soul is not that which grasps; the soul is not that which releases."},{"id":"sutra-5","num":"3.5","title":"Consciousness is not measurable — it is known through direct insight."},{"id":"sutra-6","num":"3.6","title":"They do not know the ultimate particle, nor do they know the nature of substance."},{"id":"sutra-7","num":"3.7","title":"Know the self as conscious; know the non-self as unconscious."},{"id":"sutra-8","num":"3.8","title":"Knowledge and perception do not reside in the body — they are properties of the soul alone."},{"id":"sutra-9","num":"3.9","title":"The one who realizes the soul is freed and not bound."},{"id":"sutra-10","num":"3.10","title":"Thus knowing this distinction, the learned one should stand firm in the teaching."},{"id":"sutra-11","num":"3.11","title":"Earth, water, fire, and air — these are the four elements."},{"id":"sutra-12","num":"3.12","title":"The soul is not the earth-body; the soul is not the water-body."},{"id":"sutra-13","num":"3.13","title":"The soul is not the fire-body; the soul is not the air-body."},{"id":"sutra-14","num":"3.14","title":"Distinct from these four elements, the soul is understood as something altogether different."},{"id":"sutra-15","num":"3.15","title":"The assemblage of the body — that is not the soul, say the knowers."},{"id":"sutra-16","num":"3.16","title":"Not the body, not the senses, not the mind, not the influxes — none of these is the soul."},{"id":"sutra-17","num":"3.17","title":"That which knows the states of existence — that, it is established, is the soul."},{"id":"sutra-18","num":"3.18","title":"Having known the soul thus, one does not follow after external things."},{"id":"sutra-19","num":"3.19","title":"One who understands the self also understands others."},{"id":"sutra-20","num":"3.20","title":"What is the soul of oneself is also the soul of others — truly understanding this."},{"id":"sutra-21","num":"3.21","title":"Seeing all beings equally, one should lay down the stick — causing no harm to any."},{"id":"sutra-22","num":"3.22","title":"The soul is not the doer of karma; it is not the experiencer through ego."},{"id":"sutra-23","num":"3.23","title":"With ego dissolved, having fully understood, he remains composed."},{"id":"sutra-24","num":"3.24","title":"There is no birth, no old age, no death — this is the established truth of the soul."},{"id":"sutra-25","num":"3.25","title":"This is the path of purification by which the wise are freed."},{"id":"sutra-26","num":"3.26","title":"Thus, having understood the chapter on consciousness, one knows all things fully. — iti bemi"}]},{"file":"sutrakritang-ch4.html","num":"Ch 4","title":"Ch 4 — Rejection of Error (Shatputrika)","sutras":[{"id":"hero","num":"Ch 4","title":"Rejection of Error (Shatputrika) — Attachment is the obstacle. The freed monk is free from all of it."},{"id":"sutra-1","num":"4.1","title":"The monk should not be negligent — he should not practice attachment toward women."},{"id":"sutra-2","num":"4.2","title":"The path through women increases wandering in the cycle of birth and death."},{"id":"sutra-3","num":"4.3","title":"Seeing a form he becomes pleased; hearing a voice he is captivated."},{"id":"sutra-4","num":"4.4","title":"Touch intoxicates a man; smelling fragrance he becomes greedy."},{"id":"sutra-5","num":"4.5","title":"Tasting, he becomes thirsty; his mind becomes unstable."},{"id":"sutra-6","num":"4.6","title":"One who has come under the power of the senses cannot free himself."},{"id":"sutra-7","num":"4.7","title":"The one without restraint accumulates harmful karma and is freed from it only with great suffering."},{"id":"sutra-8","num":"4.8","title":"Through attachment to women, much bondage arises."},{"id":"sutra-9","num":"4.9","title":"By such a one, the teaching cannot be practiced, nor celibacy, nor moral conduct."},{"id":"sutra-10","num":"4.10","title":"He cannot maintain non-violence, truth, or inner composure."},{"id":"sutra-11","num":"4.11","title":"The mind is agitated by it — it becomes like a fickle, unsteady thing."},{"id":"sutra-12","num":"4.12","title":"It destroys all the causes of celibacy and renunciant life."},{"id":"sutra-13","num":"4.13","title":"Like fire she burns; like a great poisonous serpent she strikes."},{"id":"sutra-14","num":"4.14","title":"Like one who drowns in deep water; like one carried away by a great flood."},{"id":"sutra-15","num":"4.15","title":"He remains on the near shore of the teaching; he has fled far from the right path."},{"id":"sutra-16","num":"4.16","title":"He drowns in the ocean of rebirth; in great fear he cannot cross over."},{"id":"sutra-17","num":"4.17","title":"Like a deer in a terrible forest, trembling at the approach of a lion."},{"id":"sutra-18","num":"4.18","title":"Like a rope that is tangled; like a dried vine wound round sandalwood."},{"id":"sutra-19","num":"4.19","title":"One who is greedy for women cannot be freed quickly."},{"id":"sutra-20","num":"4.20","title":"Gold, jewels, cows, fields, property, wealth —"},{"id":"sutra-21","num":"4.21","title":"Women — and all these possessions — are objects of clinging to which one becomes attached."},{"id":"sutra-22","num":"4.22","title":"Making attachment to these, one falls into bondage."},{"id":"sutra-23","num":"4.23","title":"The learned one, understanding this, does not become attached to women."},{"id":"sutra-24","num":"4.24","title":"The homeless one who sees equally is neither attracted nor repelled."},{"id":"sutra-25","num":"4.25","title":"He does not desire pleasures; he does not hang upon anyone."},{"id":"sutra-26","num":"4.26","title":"He does not love nor does he hate — he sees all beings equally."},{"id":"sutra-27","num":"4.27","title":"Having conquered the senses, the steadfast one does not fall into fault."},{"id":"sutra-28","num":"4.28","title":"Accomplished in the teaching, the learned one should stand firm in the teaching."},{"id":"sutra-29","num":"4.29","title":"The monk should not make attachment with any of the five kinds of beings."},{"id":"sutra-30","num":"4.30","title":"The monk who does not make attachment is purified and not bound."},{"id":"sutra-31","num":"4.31","title":"Having understood this, the monk should not make attachment dear to himself."},{"id":"sutra-32","num":"4.32","title":"Thus, having understood the teaching on rejection of error, one knows all things fully. — iti bemi"}]},{"file":"sutrakritang-ch5.html","num":"Ch 5","title":"Ch 5 — Equal Seeing (Narakavarnan)","sutras":[{"id":"hero","num":"Ch 5","title":"Equal Seeing (Narakavarnan) — Attachment is the problem — always, in every form, toward every being."},{"id":"sutra-1","num":"5.1","title":"Just as in the case of attachment to women, so too in the case of attachment to persons of the third gender."},{"id":"sutra-2","num":"5.2","title":"The monk should not be negligent — he should not practice attachment toward persons of the third gender."},{"id":"sutra-3","num":"5.3","title":"The path through this attachment also increases wandering in the cycle of birth and death."},{"id":"sutra-4","num":"5.4","title":"By such a one, the teaching cannot be practiced, nor celibacy, nor moral conduct."},{"id":"sutra-5","num":"5.5","title":"The monk who has not conquered the senses is bound and not freed."},{"id":"sutra-6","num":"5.6","title":"The learned one, understanding this, does not become attached to persons of the third gender."},{"id":"sutra-7","num":"5.7","title":"One who sees equally in all living beings — for such a one, liberation is not far."},{"id":"sutra-8","num":"5.8","title":"In the householder and in the homeless, he maintains equanimity toward all."},{"id":"sutra-9","num":"5.9","title":"He has no favorites and no enemies — he is neither attracted nor repelled."},{"id":"sutra-10","num":"5.10","title":"He recognizes the oneness of self and other."},{"id":"sutra-11","num":"5.11","title":"For all living beings equally, he wishes happiness."},{"id":"sutra-12","num":"5.12","title":"Thus, having understood the chapter on the third gender, one knows all things fully. — iti bemi"}]},{"file":"sutrakritang-ch6.html","num":"Ch 6","title":"Ch 6 — The Story of Dharma (Dharma-Katha)","sutras":[{"id":"hero","num":"Ch 6","title":"The Story of Dharma (Dharma-Katha) — What Is True Religion?"},{"id":"sutra-6-1","num":"6.1","title":"What is that religion you speak of, by which one would be freed from bondage, by which evil karma would be destroyed, and the end of suffering attaine"},{"id":"sutra-6-2","num":"6.2","title":"Non-violence, truth, non-anger, celibacy, and non-possession — this is the religion declared by the Jinas and the independently enlightened ones."},{"id":"sutra-6-3","num":"6.3","title":"Having practiced these five trainings as great vows, those who have attained inner stillness — they are the accomplished ones, the completely liberate"},{"id":"sutra-6-4","num":"6.4","title":"For those who wish to correctly practice this pure religion, there should be no killing, no giving permission to kill, and no holding of possessions."},{"id":"sutra-6-5","num":"6.5","title":"All living beings wish to live and not to die; therefore, the unattached ones completely avoid the terrible act of killing living beings."},{"id":"sutra-6-6","num":"6.6","title":"Those who are attached to sensual pleasures are not freed from bondage; those who are joined to attraction and aversion do not attain liberation."},{"id":"sutra-6-7","num":"6.7","title":"Do not commit negligence — for the negligent one, the path is not found; that monk who is given over to negligence does not attain the teaching."},{"id":"sutra-6-8","num":"6.8","title":"One alone should always practice the teaching, for the fruits and rewards are for the individual alone; all intentions belong to the individual alone,"},{"id":"sutra-6-9","num":"6.9","title":"Those who desire material gain are confused; those who desire the teaching are wise; one who teaches both gain and teaching — who among them truly kno"},{"id":"sutra-6-10","num":"6.10","title":"That which brings inner stillness — that truly is religion for the monk; just as cool water is calm, so is the monk who is at peace."},{"id":"sutra-6-11","num":"6.11","title":"The method of sacrifice that is described — it is not purifying for religion; it is combined with the killing of living beings and accompanied by untr"},{"id":"sutra-6-12","num":"6.12","title":"Those who perform fire sacrifices — they accumulate evil karma, not skillfulness; it is combined with the killing of living beings and its natural res"},{"id":"sutra-6-13","num":"6.13","title":"Those who bathe at sacred fords — purification does not come to them; they say it cleanses the self, but the evil is not washed away."},{"id":"sutra-6-14","num":"6.14","title":"Those who recite mantras and chants — they are not freed from bondage; they do not go beyond the scripture through mere recitation; thus it has been s"},{"id":"sutra-6-15","num":"6.15","title":"The brahmins who know the Vedas — they are not freed from bondage; a person attains liberation through right knowledge, right vision, and right conduc"},{"id":"sutra-6-16","num":"6.16","title":"Those who are naked and tonsured, who endure cold and heat — even they do not attain liberation, if they are not purified within."},{"id":"sutra-6-17","num":"6.17","title":"Those who propitiate gods, who follow gods out of fear — they do not attain liberation; worship of gods is without benefit for this purpose."},{"id":"sutra-6-18","num":"6.18","title":"Having understood all this, the wise one, established in the teaching, wanders forth; the learned one, endowed with humility, purifies the self by the"},{"id":"sutra-6-19","num":"6.19","title":"Non-violence is the supreme religion, instructed for all; it is proclaimed as the foremost practice, beneficial to all living beings."},{"id":"sutra-6-20","num":"6.20","title":"Truth also is the supreme religion; one should avoid falsehood; through blameless speech, the wise one speaks truth."},{"id":"sutra-6-21","num":"6.21","title":"Refraining from taking what is not given, and non-possession — whether one is an unattached monk or a householder, this is the eternal law."},{"id":"sutra-6-22","num":"6.22","title":"Celibacy is the supreme austerity; celibacy is the highest scripture; celibacy is the supreme religion; celibacy is the supreme refuge."},{"id":"sutra-6-23","num":"6.23","title":"Through austerity, having shaken off karma, restrained through the practice of meditation, having attained peace and equanimity — they become accompli"},{"id":"sutra-6-24","num":"6.24","title":"These teachings have been illuminated; hear them from me in full; they were known by the ancient ones — know them, O conquerors of the three worlds."},{"id":"sutra-6-25","num":"6.25","title":"Non-violence and equanimity — this is the eternal law. The wise and courageous ones practice this; those who have conquered the self are freed."},{"id":"sutra-6-26","num":"6.26","title":"Thus indeed was the teaching presented with equanimity by the blessed Lord, the son of the Nāya clan; this religion is declared as the one that remove"},{"id":"sutra-6-27","num":"6.27","title":"Having heard this from the teaching — the unsurpassed path to liberation — I will make this my own practice. — iti bemi (Thus I say.)"}]},{"file":"sutrakritang-ch7.html","num":"Ch 7","title":"Ch 7 — Seeds of Lower Rebirths (Khuddabhaviya)","sutras":[{"id":"hero","num":"Ch 7","title":"Seeds of Lower Rebirths (Khuddabhaviya) — Where Does Carelessness Lead?"},{"id":"sutra-7-1","num":"7.1","title":"All breathing beings, all existing beings, all living beings, all sentient beings — none should be slain, none enslaved, none harmed."},{"id":"sutra-7-2","num":"7.2","title":"One who understands this teaching — the teaching beneficial for all living beings — that person is called a wise one, who harms nothing whatsoever."},{"id":"sutra-7-3","num":"7.3","title":"Those who harm living beings — lacking wisdom, without restraint — they fall into bad destinations and weep, struck by much suffering."},{"id":"sutra-7-4","num":"7.4","title":"Earth beings, water beings, fire beings, air beings, vegetation, and mobile beings — all these living beings are equal; they should never be killed."},{"id":"sutra-7-5","num":"7.5","title":"One-sensed beings, two-sensed beings, three-sensed beings, four-sensed beings — even five-sensed beings should not be harmed: this is the mark of rest"},{"id":"sutra-7-6","num":"7.6","title":"The soul driven by the killing of living beings returns to bad destinies; therefore the wise one completely avoids the killing of living beings."},{"id":"sutra-7-7","num":"7.7","title":"All the living beings here — all those that breathe — are capable of suffering; none of them wish for death; all of them cherish life."},{"id":"sutra-7-8","num":"7.8","title":"One who strikes and destroys earth-body beings in great numbers is reborn in hell; such a person is a fool, one who has not understood."},{"id":"sutra-7-9","num":"7.9","title":"In water also there are living beings; they should never be harmed; those fools who do not know this are born in those very wombs."},{"id":"sutra-7-10","num":"7.10","title":"In vegetation also there are living beings; they should never be harmed; those fools who do not know this are born in those very wombs."},{"id":"sutra-7-11","num":"7.11","title":"For fire-body living beings, fire itself is the suffering experienced; those fools who do not know this are born in those very wombs."},{"id":"sutra-7-12","num":"7.12","title":"For air-body living beings, air itself is the suffering experienced; those fools who do not know this are born in those very wombs."},{"id":"sutra-7-13","num":"7.13","title":"The soul born into two-sensed existence through evil karma — that one becomes a worm, an insect, or an ant, just such a being as that."},{"id":"sutra-7-14","num":"7.14","title":"The soul born into three-sensed existence through evil karma — that one becomes a louse, a beetle, or a leech, just such a being as that."},{"id":"sutra-7-15","num":"7.15","title":"The soul born into four-sensed existence through evil karma — that one becomes a fly, a mosquito, or a gnat, just such a being as that."},{"id":"sutra-7-16","num":"7.16","title":"Born into the five-sensed animal realm through evil karma — one becomes a fish, a tortoise, or a snake, or a lion, a tiger, or a jackal."},{"id":"sutra-7-17","num":"7.17","title":"Thus many souls wander in the cycle of existence; those fools who do not understand do not attain liberation."},{"id":"sutra-7-18","num":"7.18","title":"These are the many stations of suffering in the world; therefore, one who desires happiness for the self should not abandon (the awareness of) sufferi"},{"id":"sutra-7-19","num":"7.19","title":"Therefore, the wise one who has understood the meaning, endowed with restraint, austerity, and humility — let such a person seek liberation."},{"id":"sutra-7-20","num":"7.20","title":"Do not cause harm to living beings, do not cause another to harm them, and do not approve of harm to them — in this way, suffering is not bound."},{"id":"sutra-7-21","num":"7.21","title":"Free from anger, free from pride, free from deceit, free from greed, one who speaks truth — having purified the self by the self, one is freed from al"},{"id":"sutra-7-22","num":"7.22","title":"One who truly knows the cycle of existence and its many forms of suffering — that one is not attached to the cycle, and is restrained through humility"},{"id":"sutra-7-23","num":"7.23","title":"O Gautama! Fearful of the fear of existence, take up the unsurpassed path of liberation — nirvana — which is the supreme happiness beyond which there "},{"id":"sutra-7-24","num":"7.24","title":"The one who is restrained and shares (what they have), sharing is the supreme austerity; one who lives with equanimity attains both the celestial real"},{"id":"sutra-7-25","num":"7.25","title":"Having heard and understood this teaching of non-violence, beneficial for all living beings — take up this teaching quickly. — iti bemi (Thus I say.)"}]},{"file":"sutrakritang-ch8.html","num":"Ch 8","title":"Ch 8 — The Great Existences (Mahababhaviya)","sutras":[{"id":"hero","num":"Ch 8","title":"The Great Existences (Mahababhaviya) — Where Does Karma Take You?"},{"id":"sutra-8-1","num":"8.1","title":"Those who are restrained, virtuous, austere, and free from passions — they are reborn in the divine realm, in purity, brightness, and excellence."},{"id":"sutra-8-2","num":"8.2","title":"In the divine realm there are pleasures, in the groves of joy and delight, in the beautiful divine chariots — and divine beings dance there."},{"id":"sutra-8-3","num":"8.3","title":"The divine beings there, enjoying divine pleasures — they reach the exhaustion of their lifespan; when the lifespan is exhausted, they fall."},{"id":"sutra-8-4","num":"8.4","title":"Therefore, though all are delighted (in heaven), through the accumulation of meritorious karma — they are not freed from existence; the wise one is no"},{"id":"sutra-8-5","num":"8.5","title":"Religion leads to heaven and to what is supreme in the world, difficult to practice; non-violence is the supreme religion, which is neither sinful nor"},{"id":"sutra-8-6","num":"8.6","title":"The radiance that exists in the divine realm — even the lord of the gods cannot follow it; the ford-maker is supreme in the world through knowledge an"},{"id":"sutra-8-7","num":"8.7","title":"Through virtue, through austerity, and through restraint always — let one cultivate the self, following along with birth, old age, and death."},{"id":"sutra-8-8","num":"8.8","title":"The austere, restrained monk, who avoids attachments, ever un-negligent, always awake — that one attains liberation."},{"id":"sutra-8-9","num":"8.9","title":"One who has renounced the four types of food, who restrains the senses, who endures hardships with steadiness — that one crosses the ocean of existenc"},{"id":"sutra-8-10","num":"8.10","title":"Hells and heavens — both are purchased by karma; the wise one, having examined karma fully, is freed from the ocean of existence."},{"id":"sutra-8-11","num":"8.11","title":"Those who commit violence in the world — unbridled, arisen in wrong ways many times — they are reborn in hell, experiencing terrible suffering."},{"id":"sutra-8-12","num":"8.12","title":"In hell there are great winds, beings of many kinds, and sharp, endless sufferings — which the hell-beings experience there."},{"id":"sutra-8-13","num":"8.13","title":"By swords, clubs, and snares, by many great spears — the hell-beings are struck there, and by the piercing thorns of the kūta-shalmali tree."},{"id":"sutra-8-14","num":"8.14","title":"They torment each other repeatedly, many torment each other; life there revolves and turns like a wheel."},{"id":"sutra-8-15","num":"8.15","title":"There is no pleasure there whatsoever; there is no peace there at any time; there are no friends, no relatives — one experiences suffering alone."},{"id":"sutra-8-16","num":"8.16","title":"This terrible hell is attained after death by those who are bound by karma; therefore, karma that leads to hell should not be done."},{"id":"sutra-8-17","num":"8.17","title":"Violence, falsehood, theft, non-celibacy, and possession — these five evils: one who (practices) these is reborn in hell."},{"id":"sutra-8-18","num":"8.18","title":"Those who do not wield force, who do not exercise force, and who are without possessions in every way — they are released from suffering."},{"id":"sutra-8-19","num":"8.19","title":"Having understood this, the wise great monk, standing in the teaching, established in the practice of meditation — is freed from all bondage."},{"id":"sutra-8-20","num":"8.20","title":"It is not possible to prevent — karma operates through what the doer does; whoever commits karma at night, that one experiences its fruit."},{"id":"sutra-8-21","num":"8.21","title":"No comparison is possible when the fruit of karma arrives; therefore, one who desires happiness for the self should prevent (the accumulation of) karm"},{"id":"sutra-8-22","num":"8.22","title":"Pleasures are impermanent; the existence in the body is impermanent; all connections are impermanent; nirvana alone is permanent, unchanging."},{"id":"sutra-8-23","num":"8.23","title":"Having shaken off karma, without craving, fearful of the terrifying cycle of existence — let one restrain the self; never be negligent at any time."},{"id":"sutra-8-24","num":"8.24","title":"Having taken the essence of the world (the true teaching), having completely renounced everything, endowed with humility — the wise one will attain li"},{"id":"sutra-8-25","num":"8.25","title":"Having heard this, the wise one attains liberation; endowed with humility, one experiences infinite happiness. — iti bemi (Thus I say.)"}]},{"file":"sutrakritang-ch9.html","num":"Ch 9","title":"Ch 9 — Samkhya (Jain Metaphysics)","sutras":[{"id":"hero","num":"Ch 9","title":"Samkhya (Jain Metaphysics) — What Is Reality Made Of?"},{"id":"sutra-9-1","num":"9.1","title":"Souls and non-souls, bondage and liberation — one who knows these correctly attains liberation."},{"id":"sutra-9-2","num":"9.2","title":"Consciousness and non-consciousness — the mark of the soul; knowing all the beings in the cycle of existence, the monk is freed."},{"id":"sutra-9-3","num":"9.3","title":"Characterized by extension, time, and modification — by color, smell, taste, touch, and shape — the non-soul is called matter."},{"id":"sutra-9-4","num":"9.4","title":"The motion-medium, the rest-medium, and space — these are declared as non-souls; also time and the modifications of substances; souls, however, are of"},{"id":"sutra-9-5","num":"9.5","title":"The modifications are not without cause — of soul and matter, of the motion-medium, the rest-medium, space, and of time — thus it has been heard."},{"id":"sutra-9-6","num":"9.6","title":"Souls are one (in kind) yet infinite in number; matter particles too are infinite; the motion-medium, the rest-medium, and space are each one; and tim"},{"id":"sutra-9-7","num":"9.7","title":"No soul ever came into being (from nothing), nor does any soul perish anywhere; the soul existed before and will continue to exist — just so."},{"id":"sutra-9-8","num":"9.8","title":"Souls who are embodied and those who are disembodied (liberated) — the body is simply matter; the soul is not stained by it."},{"id":"sutra-9-9","num":"9.9","title":"The soul, while doing karma, causes transformation in matter; bound by that, it is reborn and experiences suffering again and again."},{"id":"sutra-9-10","num":"9.10","title":"There is no gross, middle, or finest (soul) — that soul which pervades everything has never been seen by anyone."},{"id":"sutra-9-11","num":"9.11","title":"Knowledge-obscuring, perception-obscuring, deluding, and feeling-producing — karma is of eight kinds, (as declared by) the Jinas."},{"id":"sutra-9-12","num":"9.12","title":"Lifespan-determining, body-determining, status-determining, and obstructing — the eighth; these eight karmas are the causes of the soul's bondage."},{"id":"sutra-9-13","num":"9.13","title":"Wrong view, non-restraint, negligence, the passions, and activity — these five are the causes of bondage for souls in existence."},{"id":"sutra-9-14","num":"9.14","title":"One with wrong view wanders repeatedly in the world, again and again, in great darkness; the one with right view does not wander — takes up the teachi"},{"id":"sutra-9-15","num":"9.15","title":"Knowledge, right vision, and conduct — which is conduct, indeed, means keeping (the vows); these three together are the Three Jewels — thus it has bee"},{"id":"sutra-9-16","num":"9.16","title":"Partial restraint for the householder, complete restraint for the monk — both groups, through their respective (forms of restraint), practice the pure"},{"id":"sutra-9-17","num":"9.17","title":"The fourfold community of the Jina — monks, nuns, male lay-followers, female lay-followers; these four are declared as the ford of the Jina."},{"id":"sutra-9-18","num":"9.18","title":"Souls are dirtied by the filth of karma, (trapped) in the well of the cycle of existence; therefore, O wise ones, avoid karma with every effort."},{"id":"sutra-9-19","num":"9.19","title":"Anger, pride, deceit, greed — avoid them; and negligence — these five faults bind again and again."},{"id":"sutra-9-20","num":"9.20","title":"Those who serve (practice) right knowledge, right vision, and right conduct together, completely — they will attain the accomplished state, having rea"},{"id":"sutra-9-21","num":"9.21","title":"One should listen to the teachings, and always recognize the soul; one who has not fully accepted (the path) — that one is not freed, there is no doub"},{"id":"sutra-9-22","num":"9.22","title":"One who knows the opposition of the cycle of existence and liberation, and what is contrary to the teaching — for that one there is no bondage from ex"},{"id":"sutra-9-23","num":"9.23","title":"One who has no negligence, who has no possessiveness, who has neither aversion nor attachment — for that one, bondage is not found."},{"id":"sutra-9-24","num":"9.24","title":"One who understands the enumeration, who attains the enumeration — knowing the distinction between soul and non-soul — such a monk is freed."},{"id":"sutra-9-25","num":"9.25","title":"Not the Vedas, not white-robed ones, not Buddhists, not those with external marks — those who are engaged in harmful karma do not know the teaching."},{"id":"sutra-9-26","num":"9.26","title":"Equanimity toward all beings — even one step (in this direction) is great; and that which has been declared by the accomplished ones: this is the eter"},{"id":"sutra-9-27","num":"9.27","title":"Having removed the external attachments, having conquered doubt, having purified the inner — thus one is freed from bondage."},{"id":"sutra-9-28","num":"9.28","title":"One who has fully known the self sees all beings (as connected); one who speaks of the individual self speaks of the individual alone."},{"id":"sutra-9-29","num":"9.29","title":"One who knows the soul and the non-soul, supreme — for that one there is no state of \"other\" (no more taking on alien natures); that one leads the sel"},{"id":"sutra-9-30","num":"9.30","title":"The gross (body), the feeling-body, the luminous body, the karmic body — and speech modification, those are five; and the sixth is the mind modificati"},{"id":"sutra-9-31","num":"9.31","title":"That one does not accumulate karma who does not perform karma; one who does not do karma, that one attains supreme happiness."},{"id":"sutra-9-32","num":"9.32","title":"Karma has two aspects: bondage and liberation; the soul that is within bondage is in existence; the soul within liberation is declared to be liberated"},{"id":"sutra-9-33","num":"9.33","title":"One who knows bondage and liberation, supreme — those ones alone are heading toward liberation; the monk who is dispassionate from the cycle of existe"},{"id":"sutra-9-34","num":"9.34","title":"The living beings in the world who are happy, and those who are afflicted with suffering — all of them are grasped (encompassed) and protected by the "},{"id":"sutra-9-35","num":"9.35","title":"Having known this enumeration, be restrained toward all beings — embrace right conduct alone. — iti bemi (Thus I say.)"}]},{"file":"sutrakritang-ch10.html","num":"Ch 10","title":"Ch 10 — The Survey of All Existence (Vairattabhaviya)","sutras":[{"id":"hero","num":"Ch 10","title":"The Survey of All Existence (Vairattabhaviya) — How Rare Is This Birth?"},{"id":"sutra-10-1","num":"10.1","title":"Rare is human birth; rare is hearing the true teaching; rare is faith; rare too is restraint."},{"id":"sutra-10-2","num":"10.2","title":"Earth-body living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-3","num":"10.3","title":"Water-body living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-4","num":"10.4","title":"Fire-body living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-5","num":"10.5","title":"Air-body living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-6","num":"10.6","title":"Vegetation-body living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-7","num":"10.7","title":"Two-sensed living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-8","num":"10.8","title":"Three-sensed living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-9","num":"10.9","title":"Four-sensed living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-10","num":"10.10","title":"These one-sensed forms, and the five-sensed forms — you have wandered in all of these through countless births and deaths."},{"id":"sutra-10-11","num":"10.11","title":"Animal-womb living beings, existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-12","num":"10.12","title":"Even in the hell realms — living beings existing in infinite modifications — in those forms, infinitely many times, you have wandered in existence."},{"id":"sutra-10-13","num":"10.13","title":"Even as inhabitants of the divine realms — living beings existing in infinite modifications — in those forms, infinitely many times, you have wandered"},{"id":"sutra-10-14","num":"10.14","title":"Human birth is again rare — through it one is freed from all suffering; this is what I have contemplated here: the teaching that benefits all living b"},{"id":"sutra-10-15","num":"10.15","title":"One who is born into the human state, having obtained it — endowed with the teaching — know this to be rare; and rarer still is the one who accomplish"},{"id":"sutra-10-16","num":"10.16","title":"Among the capable beings in the conch-born wombs, many are born into existence; rare among them are the humans who are free from karma and have conque"},{"id":"sutra-10-17","num":"10.17","title":"In the right place, at the right time, with the right birth, in the right family, with virtue, with learning, and with strength — those humans endowed"},{"id":"sutra-10-18","num":"10.18","title":"Rare in the world even are those who have accepted right view; and among those who have accepted right view, rare is the state of complete restraint."},{"id":"sutra-10-19","num":"10.19","title":"Among the restrained, rare are the houseless wandering ascetics; and among the wandering ascetics, rare are those who attain the state of straightness"},{"id":"sutra-10-20","num":"10.20","title":"Therefore, not committing negligence, being restrained, quickly — right here, in this very birth, completely — declare the end of karma."},{"id":"sutra-10-21","num":"10.21","title":"Having understood all this, avoid — of all breathing beings — the harm; this is the proper practice for living beings: harm should not be done."},{"id":"sutra-10-22","num":"10.22","title":"Those living beings — earth-bodies, water beings, fire beings, air beings, vegetation, mobile beings, and stationary beings — all these are included i"},{"id":"sutra-10-23","num":"10.23","title":"It is not fitting to be negligent — those who do evil karma, do not do evil karma — one who desires happiness for the self."},{"id":"sutra-10-24","num":"10.24","title":"Through enumeration, the teaching declares what some do not know — the distinction between soul and non-soul, and the causes of bondage and liberation"},{"id":"sutra-10-25","num":"10.25","title":"Those who are undiscerning, with wrong view, without restraint — they do not know this; those who accumulate karma, they wander again and again."},{"id":"sutra-10-26","num":"10.26","title":"Those who know the enumeration — they attain liberation; the distinction between soul and non-soul: this is the eternal teaching."},{"id":"sutra-10-27","num":"10.27","title":"Through enumeration the soul is freed; without enumeration the soul is not freed; know both of these, then avoid evil things."},{"id":"sutra-10-28","num":"10.28","title":"Souls are equal in all eight ways; one does not harm any, does not kill any; does not gather karma — knowing this, that one is truly wise."},{"id":"sutra-10-29","num":"10.29","title":"No one destroys karma without personal effort; through personal effort one is freed; thus karma is analyzed by division."},{"id":"sutra-10-30","num":"10.30","title":"One who is the doer of karma and the experiencer of karma's fruit — that very one takes on suffering, that very one attains peace."},{"id":"sutra-10-31","num":"10.31","title":"It is not possible for another to give liberation to you; nor can another attain it for you; let one cultivate the self — one who desires happiness fo"},{"id":"sutra-10-32","num":"10.32","title":"Therefore, fearful of the fear of existence, without attachment, without possessiveness — know the one door through which one is freed from bondage."},{"id":"sutra-10-33","num":"10.33","title":"What is born, what dies, what falls, what arises — one who does not know these: that one is called undiscerning, a fool."},{"id":"sutra-10-34","num":"10.34","title":"One who knows what is being born and what is dying and what is indestructible, and what the soul falls from and what it arises into again —"},{"id":"sutra-10-35","num":"10.35","title":"That one is called wise — that one is not a fool, not without restraint; and one who knows this practices the teaching — that one is the monk."},{"id":"sutra-10-36","num":"10.36","title":"Those who are the shelter of all living beings, of all breathing beings, of all sentient beings, of everything — they are the accomplished ones, compl"},{"id":"sutra-10-37","num":"10.37","title":"All living beings wish to live and not to die; therefore, the unattached ones completely avoid the terrible act of killing."},{"id":"sutra-10-38","num":"10.38","title":"Not doing evil karma, the monk wanders in the world; knowing this teaching, through austerity and restraint."},{"id":"sutra-10-39","num":"10.39","title":"One who knows this teaching with knowledge — the wise one — evil things do not harm that one, just as water does not harm a boat."},{"id":"sutra-10-40","num":"10.40","title":"Those who do not know the teaching — through countless births and deaths — they wander without interruption through the many doubts of wombs."},{"id":"sutra-10-41","num":"10.41","title":"Thus indeed, having known the manifold suffering of the world, the wise ones stand in the teaching — they remain without agitation."},{"id":"sutra-10-42","num":"10.42","title":"Those who correctly comprehend the teaching, beneficial for all, heard — they are freed from suffering, established in the teaching, having conquered "},{"id":"sutra-10-43","num":"10.43","title":"The blessed great sage declares the teaching to those capable of liberation; the one endowed with wisdom distinguishes soul from non-soul, step by ste"},{"id":"sutra-10-44","num":"10.44","title":"Having heard this word of the Jinas, beneficial for all living beings — take up this teaching quickly. — iti bemi (Thus I say.)"}]},{"file":"sutrakritang-ch11.html","num":"Ch 11","title":"Ch 11 — The Wanderer (Pahud)","sutras":[{"id":"hero","num":"Ch 11","title":"The Wanderer (Pahud) — The Wanderer"},{"id":"sutra-1","num":"11.1","title":"This is the path of the homeless ones — those who have gone forth under the great vows."},{"id":"sutra-2","num":"11.2","title":"The monk wanders alone, moving from village to village."},{"id":"sutra-3","num":"11.3","title":"He endures cold and heat, and the biting of insects."},{"id":"sutra-4","num":"11.4","title":"He neither grieves nor rejoices — he dwells in an even state."},{"id":"sutra-5","num":"11.5","title":"The monk goes forth for alms, whether healthy or ill."},{"id":"sutra-6","num":"11.6","title":"He is not angered by others, nor pleased by their worship."},{"id":"sutra-7","num":"11.7","title":"Whatever trials come, the monk endures them all."},{"id":"sutra-8","num":"11.8","title":"Understanding living beings, he does not harm them — this is the truth of the one who is restrained."},{"id":"sutra-9","num":"11.9","title":"He does not stay the night in dwellings of the undisciplined."},{"id":"sutra-10","num":"11.10","title":"He does not settle in a place where people become bound."},{"id":"sutra-11","num":"11.11","title":"In seclusion and in solitude, he applies himself to sleeping and sitting."},{"id":"sutra-12","num":"11.12","title":"Thus the courageous one wanders, endowed with the excellence of conduct."},{"id":"sutra-13","num":"11.13","title":"Whatever the world inflicts upon him, he endures it all."},{"id":"sutra-14","num":"11.14","title":"The greedy instruct him; even the foolish lecture the learned monk."},{"id":"sutra-15","num":"11.15","title":"The arrogant repeatedly insult the monk."},{"id":"sutra-16","num":"11.16","title":"He should not weigh in his mind the suffering of the hardship he is enduring."},{"id":"sutra-17","num":"11.17","title":"Above, below, and in all directions — the monk is careful on all sides."},{"id":"sutra-18","num":"11.18","title":"He should not live together with those engaged in play and sensory enjoyment."},{"id":"sutra-19","num":"11.19","title":"He should not speak the false path, nor listen to falsehood."},{"id":"sutra-20","num":"11.20","title":"Understanding all these things, he should abandon them all."},{"id":"sutra-21","num":"11.21","title":"That monk, the homeless one, is endowed with knowledge and vision."},{"id":"sutra-22","num":"11.22","title":"He knows the self and others, knows taking and giving."},{"id":"sutra-23","num":"11.23","title":"He knows silence and composure; he knows the restrained self."},{"id":"sutra-24","num":"11.24","title":"He knows the world, knows karma, knows the channels of influx."},{"id":"sutra-25","num":"11.25","title":"That monk is not negligent, and is not attached to tastes and pleasures."},{"id":"sutra-26","num":"11.26","title":"The monk does not form attachment anywhere, even when treated with respect."},{"id":"sutra-27","num":"11.27","title":"Fields, property, livestock, family — he does not associate with attachment to relatives."},{"id":"sutra-28","num":"11.28","title":"He wanders alone, restrained, without fear of hunger or thirst."},{"id":"sutra-29","num":"11.29","title":"Without possessiveness, without ego — the learned one speaks wisely."},{"id":"sutra-30","num":"11.30","title":"Whatever is the goal of the monk — that he understands completely."},{"id":"sutra-31","num":"11.31","title":"He knows coming and going; he knows who has crossed to the other shore of the world."},{"id":"sutra-32","num":"11.32","title":"I declare this teaching for him — this has been heard, O followers of right conduct."},{"id":"sutra-33","num":"11.33","title":"Composing himself in all things, he endures all hardships."},{"id":"sutra-34","num":"11.34","title":"Such is indeed the path of the monk who has fully understood the world. — Thus I say."}]},{"file":"sutrakritang-ch12.html","num":"Ch 12","title":"Ch 12 — The Great Wanderer (Samiti-Gupti)","sutras":[{"id":"hero","num":"Ch 12","title":"The Great Wanderer (Samiti-Gupti) — The Great Wanderer"},{"id":"sutra-1","num":"12.1","title":"Of great power, great heroism — he has conquered his enemies and conquered his senses."},{"id":"sutra-2","num":"12.2","title":"That monk, walking the solitary path, is never negligent at any time."},{"id":"sutra-3","num":"12.3","title":"The austere one, restrained, courageous, of great power, under the great vows."},{"id":"sutra-4","num":"12.4","title":"Not dejected, not anxious, not deceitful, not arrogant — the great one."},{"id":"sutra-5","num":"12.5","title":"He does not associate with those attached to sense pleasures, nor does he hold contempt for anyone."},{"id":"sutra-6","num":"12.6","title":"He has no longing, no desire for anything in the world."},{"id":"sutra-7","num":"12.7","title":"He neither grieves nor rejoices in gain and loss, pleasure and pain."},{"id":"sutra-8","num":"12.8","title":"He has no thought of sensual union, no anxiety about food."},{"id":"sutra-9","num":"12.9","title":"He has conquered distraction, conquered passions, conquered the rod of karma, conquered desire."},{"id":"sutra-10","num":"12.10","title":"He is the same in wind and shade, the same in heat and cold."},{"id":"sutra-11","num":"12.11","title":"He is the same whether honored or dishonored, the same whether praised or not."},{"id":"sutra-12","num":"12.12","title":"The man who has never found this before — for him this teaching is appropriate."},{"id":"sutra-13","num":"12.13","title":"Of great power, great heroism — free from impurities, free from garlands."},{"id":"sutra-14","num":"12.14","title":"Without weapon or scripture as shelter, without fear, without possessions, without attachment."},{"id":"sutra-15","num":"12.15","title":"Understanding this path, he has gone forth correctly here in this world."},{"id":"sutra-16","num":"12.16","title":"Understanding the five senses, he is restrained, moving lightly."},{"id":"sutra-17","num":"12.17","title":"Unattached to touch, form, sound, taste, and smell."},{"id":"sutra-18","num":"12.18","title":"Sound, form, touch, taste, smell — the five sensory engagements."},{"id":"sutra-19","num":"12.19","title":"Those great seekers in the world who are detached and have passed beyond enjoyments."},{"id":"sutra-20","num":"12.20","title":"Having fully understood this teaching, and those others who have done likewise."},{"id":"sutra-21","num":"12.21","title":"He has fully understood scripture, conduct, and austerity — radiant with inner brilliance."},{"id":"sutra-22","num":"12.22","title":"For the undisciplined householder, a higher standard of conduct now becomes appropriate."},{"id":"sutra-23","num":"12.23","title":"Thus the one of great splendor does not delight in sensory enjoyments."},{"id":"sutra-24","num":"12.24","title":"Whatever passions exist in the world — all of them he has fully understood."},{"id":"sutra-25","num":"12.25","title":"The one of great power, free from attachment, free from aversion, free from delusion."},{"id":"sutra-26","num":"12.26","title":"One does not succeed through attachment, nor is one liberated through aversion."},{"id":"sutra-27","num":"12.27","title":"Seized by delusion, one wanders in the cycle of birth and death."},{"id":"sutra-28","num":"12.28","title":"He should always have right vision and always abandon delusion."},{"id":"sutra-29","num":"12.29","title":"The one with right vision always understands the bondage of karma."},{"id":"sutra-30","num":"12.30","title":"Understanding this path, the monk follows it."},{"id":"sutra-31","num":"12.31","title":"Freed from all suffering, having crossed to the far shore of the cycle of rebirth."},{"id":"sutra-32","num":"12.32","title":"That monk of great power has conquered all hardships, conquered all afflictions."},{"id":"sutra-33","num":"12.33","title":"The soul is bound by karma; the soul is freed by karma."},{"id":"sutra-34","num":"12.34","title":"He who truly understands the teaching is freed from suffering."},{"id":"sutra-35","num":"12.35","title":"He has no entanglement in the world who has no sense of \"mine.\""},{"id":"sutra-36","num":"12.36","title":"There is no burden for him, as one stands even on a scale."},{"id":"sutra-37","num":"12.37","title":"This is the great splendor, great power, great heroism of that one."},{"id":"sutra-38","num":"12.38","title":"He has the strength of one who is himself the authority."},{"id":"sutra-39","num":"12.39","title":"That monk, walking the solitary path, maintains all restraint."},{"id":"sutra-40","num":"12.40","title":"He knows this entire world; he knows the domain of taking and giving."},{"id":"sutra-41","num":"12.41","title":"That courageous, powerful one — the learned one knows the teaching."},{"id":"sutra-42","num":"12.42","title":"He arrives at the excellent teaching, his karma worn away."},{"id":"sutra-43","num":"12.43","title":"He does not commit harmful actions, not even many small ones."},{"id":"sutra-44","num":"12.44","title":"He does not speak falsehood, does not speak harsh words."},{"id":"sutra-45","num":"12.45","title":"The monk of composed mind does not fail anywhere."},{"id":"sutra-46","num":"12.46","title":"Entering the householder's home, he dwells in an even state."},{"id":"sutra-47","num":"12.47","title":"Having fully understood this teaching, through restraint and austerity."},{"id":"sutra-48","num":"12.48","title":"He is the great one of power who has fully understood the world."},{"id":"sutra-49","num":"12.49","title":"That monk of great power, having fully understood the world. — Thus I say."}]},{"file":"sutrakritang-ch13.html","num":"Ch 13","title":"Ch 13 — Shramana-Brahman (Shulagava)","sutras":[{"id":"hero","num":"Ch 13","title":"Shramana-Brahman (Shulagava) — The True Monk and the Brahmin Scholar"},{"id":"sutra-1","num":"13.1","title":"The wise person knows what is good and what is harmful in the world."},{"id":"sutra-2","num":"13.2","title":"The one with right vision knows non-violence and truth."},{"id":"sutra-3","num":"13.3","title":"The external one devoted to learning and hearing much does not know the teaching."},{"id":"sutra-4","num":"13.4","title":"The Brahmin who has studied the Vedas by the thousand — yet still harms living beings."},{"id":"sutra-5","num":"13.5","title":"He is not a true monk, he is not a true Brahmin."},{"id":"sutra-6","num":"13.6","title":"The truly learned one is always absorbed in truth, disciplined in virtue and restraint."},{"id":"sutra-7","num":"13.7","title":"The true Brahmin, the true monk — that is the true mendicant."},{"id":"sutra-8","num":"13.8","title":"The Brahmin who is restrained, courageous, does not transgress right conduct."},{"id":"sutra-9","num":"13.9","title":"For those awakened at the ford, who have no other refuge."},{"id":"sutra-10","num":"13.10","title":"The one with right vision, detached, is not a servant of karma."},{"id":"sutra-11","num":"13.11","title":"This is true Brahminhood; this is the excellent monkhood."},{"id":"sutra-12","num":"13.12","title":"Precisely here is the true Brahmin called wise; precisely here is the monk so called."},{"id":"sutra-13","num":"13.13","title":"The Brahmin who tends fires and performs oblations."},{"id":"sutra-14","num":"13.14","title":"He harms living beings without knowing it — what will that Brahmin accomplish?"},{"id":"sutra-15","num":"13.15","title":"The Brahmin who has heard much, who is devoted to learning, who is greatly learned."},{"id":"sutra-16","num":"13.16","title":"For the sake of wealth and worldly goods, that one strives with great effort."},{"id":"sutra-17","num":"13.17","title":"He is not endowed with monkhood, he is not endowed with true Brahminhood."},{"id":"sutra-18","num":"13.18","title":"The Brahmin who performs actions according to birth-rites and ceremonies."},{"id":"sutra-19","num":"13.19","title":"In birth-rites and marriages, let there be no killing of any kind."},{"id":"sutra-20","num":"13.20","title":"This is truly the Brahmin; this is truly the renunciant."},{"id":"sutra-21","num":"13.21","title":"The true teaching has been declared; the learned one moves within it."},{"id":"sutra-22","num":"13.22","title":"Having fully understood the teaching and restraint, the great one knows."},{"id":"sutra-23","num":"13.23","title":"The learned monk is the one who has fully understood living and non-living beings."},{"id":"sutra-24","num":"13.24","title":"Having understood living and non-living, he should avoid karma."},{"id":"sutra-25","num":"13.25","title":"Harming living beings, taking what is not given, deceit, falsehood, and possessiveness."},{"id":"sutra-26","num":"13.26","title":"These five great vows — the learned one knows them all."},{"id":"sutra-27","num":"13.27","title":"Non-violence, truth in deed, and the non-taking of what is not given."},{"id":"sutra-28","num":"13.28","title":"Celibacy and the rule of non-possessiveness and restraint."},{"id":"sutra-29","num":"13.29","title":"Having fully understood this teaching, he is both the Brahmin and the monk."},{"id":"sutra-30","num":"13.30","title":"Through knowledge, through right perception, through conduct, through austerity."},{"id":"sutra-31","num":"13.31","title":"In these lies the essence of the teaching, as the wise ones know."},{"id":"sutra-32","num":"13.32","title":"Those who do not know the teaching are bound from beginningless time."},{"id":"sutra-33","num":"13.33","title":"Those who truly know the teaching become liberated."},{"id":"sutra-34","num":"13.34","title":"Having heard and understood this, he is detached and knows the ocean of existence."},{"id":"sutra-35","num":"13.35","title":"Thus the true Brahmin, the true monk, knows the teaching completely. — Thus I say."}]},{"file":"sutrakritang-ch14.html","num":"Ch 14","title":"Ch 14 — Village Religion (Gramadharma)","sutras":[{"id":"hero","num":"Ch 14","title":"Village Religion (Gramadharma) — The Monk Who Moves Through the World"},{"id":"sutra-14-1","num":"14.1","title":"Village and city, forest and mountain cave."},{"id":"sutra-14-2","num":"14.2","title":"The restrained, disciplined monk wanders with equanimity."},{"id":"sutra-14-3","num":"14.3","title":"He moves from village to village and is not attached to any household."},{"id":"sutra-14-4","num":"14.4","title":"He should be composed everywhere — this is the excellent vow of virtue."},{"id":"sutra-14-5","num":"14.5","title":"He does not associate excessively with relatives in households, nor is he attached to tastes and pleasures."},{"id":"sutra-14-6","num":"14.6","title":"He should seek food when it is offered openly and publicly."},{"id":"sutra-14-7","num":"14.7","title":"He should eat little there, so that no remainder is left."},{"id":"sutra-14-8","num":"14.8","title":"He should not stay where women are not properly regulated."},{"id":"sutra-14-9","num":"14.9","title":"He should tend to sleeping and sitting in seclusion."},{"id":"sutra-14-10","num":"14.10","title":"He should not become angry, not laugh excessively, not be idle."},{"id":"sutra-14-11","num":"14.11","title":"He should not create quarrels or opposition, nor declare falsehood."},{"id":"sutra-14-12","num":"14.12","title":"Thus the monk wanders through village and city in all directions."},{"id":"sutra-14-13","num":"14.13","title":"Going on the alms round, he approaches the householder for food."},{"id":"sutra-14-14","num":"14.14","title":"He should seek alms neither for himself alone nor for others alone."},{"id":"sutra-14-15","num":"14.15","title":"Whatever is received, pure or mixed, the restrained one should eat it."},{"id":"sutra-14-16","num":"14.16","title":"The monk should not feel resentment or joy over whatever alms he receives."},{"id":"sutra-14-17","num":"14.17","title":"He did not go forth for the sake of food; he went forth for the sake of the teaching."},{"id":"sutra-14-18","num":"14.18","title":"The monk is careful about living beings and restrained in seeking food."},{"id":"sutra-14-19","num":"14.19","title":"He does not prepare anything himself, does not have others prepare anything."},{"id":"sutra-14-20","num":"14.20","title":"Whatever pure seats are there, the monk uses them accordingly."},{"id":"sutra-14-21","num":"14.21","title":"He should not enter the householder's home at an inappropriate time."},{"id":"sutra-14-22","num":"14.22","title":"He should not set down his alms bowl to beg, nor refuse what is offered."},{"id":"sutra-14-23","num":"14.23","title":"Women, men, monks — all in the householder's household."},{"id":"sutra-14-24","num":"14.24","title":"He should not be attached to any of them — thus he conducts the alms round."},{"id":"sutra-14-25","num":"14.25","title":"The householder should know that what is given to the monk is spiritual gain in future lives."},{"id":"sutra-14-26","num":"14.26","title":"This is the householder's duty — to serve the monk with reverence."},{"id":"sutra-14-27","num":"14.27","title":"He should move aside respectfully and honor the monk as deserved."},{"id":"sutra-14-28","num":"14.28","title":"A seat, water, and food that is pure in the right way — these he should give."},{"id":"sutra-14-29","num":"14.29","title":"He should not give to one who is not deserving; he should always give to one who is deserving."},{"id":"sutra-14-30","num":"14.30","title":"He who is established in the householder's household — he knows what is established in the teaching."},{"id":"sutra-14-31","num":"14.31","title":"He knows liberation and bondage as well."},{"id":"sutra-14-32","num":"14.32","title":"Those who are established in virtue in the world — they walk the teaching, those good ones."},{"id":"sutra-14-33","num":"14.33","title":"Having understood this teaching, the householder correctly receives it."},{"id":"sutra-14-34","num":"14.34","title":"In this way he wanders among the householder households with equanimity."},{"id":"sutra-14-35","num":"14.35","title":"This alone one should practice, whoever desires to be skilled."},{"id":"sutra-14-36","num":"14.36","title":"Having heard and understood this, he should follow this path."},{"id":"sutra-14-37","num":"14.37","title":"Toward all living beings — wandering with equanimity."},{"id":"sutra-14-38","num":"14.38","title":"This is the teaching of the great seeker; there is no other anywhere."},{"id":"sutra-14-39","num":"14.39","title":"Having arrived at the path, he moves lightly."},{"id":"sutra-14-40","num":"14.40","title":"He should not speak falsehood, should not speak harsh words."},{"id":"sutra-14-41","num":"14.41","title":"He should not speak falsehood in the world, nor act from anger or pride."},{"id":"sutra-14-42","num":"14.42","title":"Understanding all these, he should abandon all of them."},{"id":"sutra-14-43","num":"14.43","title":"Composed in that path, having heard and understood this."},{"id":"sutra-14-44","num":"14.44","title":"Thus the monk moves lightly, restrained and virtuous everywhere. — Thus I say."}]},{"file":"sutrakritang-ch15.html","num":"Ch 15","title":"Ch 15 — Questions for the Knower (Nganathaputra)","sutras":[{"id":"hero","num":"Ch 15","title":"Questions for the Knower (Nganathaputra) — What Is the Path? What Is Bondage?"},{"id":"sutra-15-1","num":"15.1","title":"What is the path? What is bondage? Lord, this we ask you."},{"id":"sutra-15-2","num":"15.2","title":"The souls — with consciousness and without consciousness — should be understood."},{"id":"sutra-15-3","num":"15.3","title":"The conscious one gets entangled; the non-conscious arises from the conscious."},{"id":"sutra-15-4","num":"15.4","title":"Thus bondage has been described; and this is the procedure for liberation."},{"id":"sutra-15-5","num":"15.5","title":"No anger, no pride, no deceit, no greed."},{"id":"sutra-15-6","num":"15.6","title":"He conquers anger, conquers pride, conquers deceit, conquers greed."},{"id":"sutra-15-7","num":"15.7","title":"He does not do, does not cause to be done, does not approve of harming living beings."},{"id":"sutra-15-8","num":"15.8","title":"Thus, Lord, is the path; and thus is bondage."},{"id":"sutra-15-9","num":"15.9","title":"What is liberation, Lord, we ask? And what is liberation from suffering?"},{"id":"sutra-15-10","num":"15.10","title":"He who truly understands the teaching is freed from all suffering."},{"id":"sutra-15-11","num":"15.11","title":"He knows bondage and liberation; he knows the world as beginningless."},{"id":"sutra-15-12","num":"15.12","title":"He should always have right vision, and abandon the worldly view."},{"id":"sutra-15-13","num":"15.13","title":"He should not do harmful acts, should not cause others to do them."},{"id":"sutra-15-14","num":"15.14","title":"He should know this himself, and understand it completely."},{"id":"sutra-15-15","num":"15.15","title":"Having understood exactly this, he should follow this path."},{"id":"sutra-15-16","num":"15.16","title":"Having heard and understood this, composed in this path."},{"id":"sutra-15-17","num":"15.17","title":"What are the signs of the one who has gone forth? What are the signs of the devoted follower?"},{"id":"sutra-15-18","num":"15.18","title":"For the one who has gone forth and for the devoted follower — these are the signs."},{"id":"sutra-15-19","num":"15.19","title":"The learned one gives fearlessness to all living beings."},{"id":"sutra-15-20","num":"15.20","title":"He is not averse to others, not attached to sensory enjoyments."},{"id":"sutra-15-21","num":"15.21","title":"Having understood living and non-living, he avoids karma."},{"id":"sutra-15-22","num":"15.22","title":"He moves lightly everywhere, without losing anything of his conduct."},{"id":"sutra-15-23","num":"15.23","title":"Knowing exactly this becomes the cause of liberation."},{"id":"sutra-15-24","num":"15.24","title":"Having heard this, the courageous monk is composed in this path. — Thus I say."}]},{"file":"sutrakritang-ch16.html","num":"Ch 16","title":"Ch 16 — The Scripture Repository (Ganipidag)","sutras":[{"id":"hero","num":"Ch 16","title":"The Scripture Repository (Ganipidag) — The Seal of Book One"},{"id":"sutra-16-1","num":"16.1","title":"This has been heard from the Blessed One — know the teaching, O learned ones."},{"id":"sutra-16-2","num":"16.2","title":"Right vision, and conduct, and austerity, and restraint."},{"id":"sutra-16-3","num":"16.3","title":"This is the essence of the teaching, as the learned ones know."},{"id":"sutra-16-4","num":"16.4","title":"The monk who is established in this burns away karma."},{"id":"sutra-16-5","num":"16.5","title":"He gives fearlessness to all living beings from all sides."},{"id":"sutra-16-6","num":"16.6","title":"He does not harm, does not cause harm to living beings in any way."},{"id":"sutra-16-7","num":"16.7","title":"Composed in exactly this, under exactly the great vows."},{"id":"sutra-16-8","num":"16.8","title":"This is the essence of everything — having understood it, he wanders."},{"id":"sutra-16-9","num":"16.9","title":"This has been heard and declared by the Blessed One, having fully comprehended it."},{"id":"sutra-16-10","num":"16.10","title":"The monk who is established in this burns away excellent karma."},{"id":"sutra-16-11","num":"16.11","title":"That monk, moving lightly, listens to all living beings."},{"id":"sutra-16-12","num":"16.12","title":"Having understood this path, that monk is not negligent."},{"id":"sutra-16-13","num":"16.13","title":"This teaching has been heard — know it thus, O learned ones."},{"id":"sutra-16-14","num":"16.14","title":"This indeed is the teaching of all teachings — know it as the highest in the world."},{"id":"sutra-16-15","num":"16.15","title":"This has been heard and declared by the Blessed One, having fully comprehended it. The monk who is established in this — he burns away his karma. — Th"}]},{"file":"sutrakritang-ch17.html","num":"Ch 17","title":"Ch 17 — Papasramana (False Monks)","sutras":[{"id":"hero","num":"Ch 17","title":"Papasramana (False Monks) — False Monks & Evil Ascetics"},{"id":"sutra-1","num":"17.1","title":"Listen to me, O monks — the characteristics of the evil ascetic."},{"id":"sutra-2","num":"17.2","title":"Outwardly the head is shaved; inwardly one indulges in passion."},{"id":"sutra-3","num":"17.3","title":"He renounces clothing permanently, yet in mind he enjoys sensual pleasures."},{"id":"sutra-4","num":"17.4","title":"Inside he is driven by anger; outside he speaks of forgiveness."},{"id":"sutra-5","num":"17.5","title":"He nourishes pride within, yet speaks of moral discipline with his mouth."},{"id":"sutra-6","num":"17.6","title":"Deception belongs to the deceiver — wearing the external marks of a holy one."},{"id":"sutra-7","num":"17.7","title":"He nourishes greed in the world of rebirth, while externally he practices mendicancy."},{"id":"sutra-8","num":"17.8","title":"That is not true religion which has not entered within — even if it is practiced outwardly."},{"id":"sutra-9","num":"17.9","title":"What is the fruit of hearing the teaching, for one whose mind is attached to sense objects?"},{"id":"sutra-10","num":"17.10","title":"Through external restraint — but internally, there are still bonds."},{"id":"sutra-11","num":"17.11","title":"Anger, pride, deception, greed — these four are the causes of evil karma."},{"id":"sutra-12","num":"17.12","title":"By anger he harms friends; by pride he harms teachers."},{"id":"sutra-13","num":"17.13","title":"Through deception comes wrong belief; through greed comes possessiveness."},{"id":"sutra-14","num":"17.14","title":"One who does not abandon these four — he is evil."},{"id":"sutra-15","num":"17.15","title":"He is called a monk, but is not one in truth."},{"id":"sutra-16","num":"17.16","title":"He does not abide in non-violence; he is devoid of all restraint."},{"id":"sutra-17","num":"17.17","title":"Seized by the passions, he harms many living beings in the world."},{"id":"sutra-18","num":"17.18","title":"A being does not attain liberation as long as the passions are not exhausted."},{"id":"sutra-19","num":"17.19","title":"Therefore the wise one should turn back from all evils."},{"id":"sutra-20","num":"17.20","title":"The evil ascetic is not restrained, not a sage, not a true renouncer."},{"id":"sutra-21","num":"17.21","title":"But one who has compassion for all beings and practices non-violence —"},{"id":"sutra-22","num":"17.22","title":"He is truly a monk with well-practiced religion, free from evil karma."},{"id":"sutra-23","num":"17.23","title":"Having conquered the senses, having conquered the passions, equanimous in all situations, truly restrained."},{"id":"sutra-24","num":"17.24","title":"He does not desire anything; he does not hold aversion toward anything."},{"id":"sutra-25","num":"17.25","title":"He practices the teaching in accordance with the teaching; pure, he acts with purity."},{"id":"sutra-26","num":"17.26","title":"He does not praise himself; he does not condemn others."},{"id":"sutra-27","num":"17.27","title":"Regarding all living beings with compassion — as oneself, so others."},{"id":"sutra-28","num":"17.28","title":"This is the mark of a true monk — not outer form."},{"id":"sutra-29","num":"17.29","title":"One who knows this teaching — he is established in the teaching."},{"id":"sutra-30","num":"17.30","title":"Externally wearing the ascetic's guise, internally holding wrong views — such a one is an evil monk; his religion is not well-practiced. — Thus I say."}]},{"file":"sutrakritang-ch18.html","num":"Ch 18","title":"Ch 18 — Raniyam (The Queen's Path)","sutras":[{"id":"hero","num":"Ch 18","title":"Raniyam (The Queen's Path) — The Queen's Path"},{"id":"sutra-1","num":"18.1","title":"In the city of Rajagriha there lived a queen named Mrigavati."},{"id":"sutra-2","num":"18.2","title":"She possessed great wealth and riches, yet she had grown weary of sensual enjoyments."},{"id":"sutra-3","num":"18.3","title":"She heard of the Blessed One — Mahavira, the Conqueror, in the world."},{"id":"sutra-4","num":"18.4","title":"She went to his assembly to hear the beautiful teaching."},{"id":"sutra-5","num":"18.5","title":"Having heard the teaching and having been blessed by the Blessed One —"},{"id":"sutra-6","num":"18.6","title":"She reflected: \"This royal wealth is not my refuge.\""},{"id":"sutra-7","num":"18.7","title":"Through austerity, restraint, and moral discipline, she turns back from the cycle of existence."},{"id":"sutra-8","num":"18.8","title":"This queen is truly courageous — she has entered the teaching of the Conqueror."},{"id":"sutra-9","num":"18.9","title":"Not birth, not family, not strength, not beauty, not age —"},{"id":"sutra-10","num":"18.10","title":"Not wealth, not kingdom — these are not causes of liberation."},{"id":"sutra-11","num":"18.11","title":"Destroying karma in particular ways, one aspires to liberation."},{"id":"sutra-12","num":"18.12","title":"A king can be freed through this; a slave can be freed through this."},{"id":"sutra-13","num":"18.13","title":"A woman can be freed through this; a man can be freed through this."},{"id":"sutra-14","num":"18.14","title":"A householder woman can take up the path; an ordained nun can take up the path."},{"id":"sutra-15","num":"18.15","title":"With mind settled in the teaching, he knows the one who has crossed the ocean of existence."},{"id":"sutra-16","num":"18.16","title":"Neither family, nor birth caste, nor outer appearance mark the sage."},{"id":"sutra-17","num":"18.17","title":"Purified by austerity and restraint, with clear mind in the Jina's teaching —"},{"id":"sutra-18","num":"18.18","title":"One who upholds the entire teaching — he is called a monk in this world."},{"id":"sutra-19","num":"18.19","title":"Just as the lotus is born in water, yet is not stained by water —"},{"id":"sutra-20","num":"18.20","title":"In this way, monks and nuns are not stained by the cycle of existence."},{"id":"sutra-21","num":"18.21","title":"Queen Mrigavati, purified, went forth into the renunciant life."},{"id":"sutra-22","num":"18.22","title":"She practices severe austerity; she lives by restraint."},{"id":"sutra-23","num":"18.23","title":"She does not grieve for the kingdom; she does not exult in her austerity."},{"id":"sutra-24","num":"18.24","title":"Royal wealth is not liberation — through austerity and restraint one is freed."},{"id":"sutra-25","num":"18.25","title":"Royal wealth is not liberation — through austerity and restraint one is freed; one who correctly takes up the path is released. — Thus I say."}]},{"file":"sutrakritang-ch19.html","num":"Ch 19","title":"Ch 19 — Sevala (The Solitary Monk)","sutras":[{"id":"hero","num":"Ch 19","title":"Sevala (The Solitary Monk) — The Solitary Monk"},{"id":"sutra-1","num":"19.1","title":"A monk should stand alone; a monk should sleep alone."},{"id":"sutra-2","num":"19.2","title":"One practices restraint alone; one endures hardship alone."},{"id":"sutra-3","num":"19.3","title":"One is born by oneself; one dies by oneself."},{"id":"sutra-4","num":"19.4","title":"One binds karma alone; one is freed alone."},{"id":"sutra-5","num":"19.5","title":"Contentment in solitude is attained only by the rare few."},{"id":"sutra-6","num":"19.6","title":"Having cultivated solitude, the wise monk comes to understand everything."},{"id":"sutra-7","num":"19.7","title":"He should act with equanimity on all sides; he should not perceive occasions for discrimination."},{"id":"sutra-8","num":"19.8","title":"Alone I stand; alone the wise one; alone, established in the teaching."},{"id":"sutra-9","num":"19.9","title":"In solitude there is the danger of wrong path; in solitude there is the danger of negligence."},{"id":"sutra-10","num":"19.10","title":"In solitude there arises pride; in solitude there arises despondency."},{"id":"sutra-11","num":"19.11","title":"In solitude there is failure of right practice; in solitude there is transgression of the path."},{"id":"sutra-12","num":"19.12","title":"Going alone, wandering alone — one can fall into untrustworthiness."},{"id":"sutra-13","num":"19.13","title":"The wise ones do not universally praise solitude — all the knowledgeable ones understand this."},{"id":"sutra-14","num":"19.14","title":"Both solitude and community — the restrained one knows both."},{"id":"sutra-15","num":"19.15","title":"Not attached to crowds, not attached to display, not attached to others."},{"id":"sutra-16","num":"19.16","title":"The monk should contemplate the self by the self — unsupported."},{"id":"sutra-17","num":"19.17","title":"He is alone in all the world — the soul bearing its previously made karma."},{"id":"sutra-18","num":"19.18","title":"There is no helper for him; there is no relative for him."},{"id":"sutra-19","num":"19.19","title":"Therefore one who dwells in solitude should understand the aloneness of the self."},{"id":"sutra-20","num":"19.20","title":"One should stand alone, one should sleep alone, one should wander alone. The wise monk understands both solitude and community. — Thus I say."}]},{"file":"sutrakritang-ch20.html","num":"Ch 20","title":"Ch 20 — Sthananga (The Fourfold Order)","sutras":[{"id":"hero","num":"Ch 20","title":"Sthananga (The Fourfold Order) — The Fourfold Order"},{"id":"sutra-1","num":"20.1","title":"Monks, nuns, laymen, and laywomen — the community is fourfold."},{"id":"sutra-2","num":"20.2","title":"For monks there are five great vows; for laypeople there are five small vows."},{"id":"sutra-3","num":"20.3","title":"For monks, non-violence comes first — one should not harm any living being."},{"id":"sutra-4","num":"20.4","title":"For monks, truth in speech, and truth of mind and material reality."},{"id":"sutra-5","num":"20.5","title":"The monk does not take what is not given — for monks, there is no theft."},{"id":"sutra-6","num":"20.6","title":"For monks, celibacy — in all aspects of being."},{"id":"sutra-7","num":"20.7","title":"Non-possessiveness for monks — one should desire nothing."},{"id":"sutra-8","num":"20.8","title":"These five great vows are declared to be the restraint of monks."},{"id":"sutra-9","num":"20.9","title":"For nuns too, the great vows are the same five."},{"id":"sutra-10","num":"20.10","title":"The nun too practices non-violence — equal in all respects."},{"id":"sutra-11","num":"20.11","title":"The nun, having understood truth, practices it in all aspects."},{"id":"sutra-12","num":"20.12","title":"The nun neither takes what is not given, nor causes others to take it."},{"id":"sutra-13","num":"20.13","title":"For nuns, celibacy and severe austerity."},{"id":"sutra-14","num":"20.14","title":"The nun does not possess, does not desire, does not enjoy possessions."},{"id":"sutra-15","num":"20.15","title":"She is well-established on the path to liberation."},{"id":"sutra-16","num":"20.16","title":"For monks and for nuns, the teaching is the same."},{"id":"sutra-17","num":"20.17","title":"For laypeople, the five small vows — as declared by the Jina."},{"id":"sutra-18","num":"20.18","title":"The layman abstains from gross violence, according to his capacity."},{"id":"sutra-19","num":"20.19","title":"The layman avoids falsehood — major falsehood in particular."},{"id":"sutra-20","num":"20.20","title":"The layman does not take what is not given — avoiding major theft."},{"id":"sutra-21","num":"20.21","title":"For the layperson, the avoidance of another's spouse."},{"id":"sutra-22","num":"20.22","title":"The layperson limits possessions — according to capacity."},{"id":"sutra-23","num":"20.23","title":"These five small vows, well-practiced by laypeople."},{"id":"sutra-24","num":"20.24","title":"The pure layperson — he too is on the path to liberation."},{"id":"sutra-25","num":"20.25","title":"All four study and practice — one teaching of the Jinas."},{"id":"sutra-26","num":"20.26","title":"Monks, nuns, laymen, laywomen — they support one another."},{"id":"sutra-27","num":"20.27","title":"Laypeople give food to monks — they are thus connected to merit."},{"id":"sutra-28","num":"20.28","title":"Monks transmit the teaching — always for the benefit of laypeople."},{"id":"sutra-29","num":"20.29","title":"This fourfold community is honored by gods and humans."},{"id":"sutra-30","num":"20.30","title":"Monks and nuns, laymen and laywomen — all four study and practice. This is the teaching of the Jinas. — Thus I say."}]},{"file":"sutrakritang-ch21.html","num":"Ch 21","title":"Ch 21 — Nirgrantha-pravachana (The Jain Teaching)","sutras":[{"id":"hero","num":"Ch 21","title":"Nirgrantha-pravachana (The Jain Teaching) — The Jain Teaching"},{"id":"sutra-1","num":"21.1","title":"The soul exists in the world — this is what the Jinas have proclaimed."},{"id":"sutra-2","num":"21.2","title":"The soul is both the agent of action and the experiencer of karma's fruits."},{"id":"sutra-3","num":"21.3","title":"There is bondage for the soul — brought about by karma."},{"id":"sutra-4","num":"21.4","title":"There is the shedding of karma; there is the stopping of new karma."},{"id":"sutra-5","num":"21.5","title":"There is liberation for the soul — through the exhaustion of karma."},{"id":"sutra-6","num":"21.6","title":"These five existents — proclaimed by the Jinas."},{"id":"sutra-7","num":"21.7","title":"One who has faith in these — he is called a Nirgrantha."},{"id":"sutra-8","num":"21.8","title":"Not made by a god, not made by fate — made by karma."},{"id":"sutra-9","num":"21.9","title":"Passion, aversion, and delusion — three causes of karmic bondage."},{"id":"sutra-10","num":"21.10","title":"Just as a burnt seed does not germinate — when karma is exhausted, it does not arise again."},{"id":"sutra-11","num":"21.11","title":"Right knowledge, right faith, right conduct — the three jewels."},{"id":"sutra-12","num":"21.12","title":"These three jewels — they belong to the Nirgranthas."},{"id":"sutra-13","num":"21.13","title":"Right faith is the first jewel; right knowledge the second; right conduct the third."},{"id":"sutra-14","num":"21.14","title":"Without right faith, knowledge is not pure."},{"id":"sutra-15","num":"21.15","title":"Without right knowledge, conduct is not pure."},{"id":"sutra-16","num":"21.16","title":"Therefore the wise one takes up all three together."},{"id":"sutra-17","num":"21.17","title":"The teaching of the Nirgranthas is pure — throughout all the world."},{"id":"sutra-18","num":"21.18","title":"Not found elsewhere; not taught by others."},{"id":"sutra-19","num":"21.19","title":"The teaching of the Jinas is without beginning; it is eternal."},{"id":"sutra-20","num":"21.20","title":"The path to liberation proclaimed by the Jinas — it is not obtained from others."},{"id":"sutra-21","num":"21.21","title":"Therefore the wise one should take up the teaching of the Nirgranthas."},{"id":"sutra-22","num":"21.22","title":"Maintaining the three jewels, one goes to liberation."},{"id":"sutra-23","num":"21.23","title":"What are the marks of right faith? I will speak according to my understanding."},{"id":"sutra-24","num":"21.24","title":"Right faith is trust in the Jinas, the teaching, and the community."},{"id":"sutra-25","num":"21.25","title":"The marks of right faith: free of doubt, free of desire for the teaching's fruits."},{"id":"sutra-26","num":"21.26","title":"The mark of right knowledge: understanding the nature of the soul and matter."},{"id":"sutra-27","num":"21.27","title":"Knowledge of the five categories of existence is right knowledge. ⚠️"},{"id":"sutra-28","num":"21.28","title":"The mark of right conduct is non-violence."},{"id":"sutra-29","num":"21.29","title":"Restraint and austerity are right conduct, according to the Jinas."},{"id":"sutra-30","num":"21.30","title":"Through right conduct there is the exhaustion of karma."},{"id":"sutra-31","num":"21.31","title":"One who is established in right faith — he is established in the teaching."},{"id":"sutra-32","num":"21.32","title":"One who is established in right knowledge — he is approaching liberation."},{"id":"sutra-33","num":"21.33","title":"One who is established in right conduct — he exhausts karma."},{"id":"sutra-34","num":"21.34","title":"The one endowed with the three jewels aspires to liberation."},{"id":"sutra-35","num":"21.35","title":"The soul exists; bondage exists; liberation exists. This is what the Jinas have proclaimed — one who correctly has faith in this is on the path. — Thu"}]},{"file":"sutrakritang-ch22.html","num":"Ch 22","title":"Ch 22 — Mahasramana (The Great Monk)","sutras":[{"id":"hero","num":"Ch 22","title":"Mahasramana (The Great Monk) — The Great Monk"},{"id":"sutra-1","num":"22.1","title":"He is called the Great Monk who is beneficial to all beings."},{"id":"sutra-2","num":"22.2","title":"He does not harm, does not cause harm, does not approve of those who harm."},{"id":"sutra-3","num":"22.3","title":"One-sensed, two-sensed, three-sensed, four-sensed —"},{"id":"sutra-4","num":"22.4","title":"And five-sensed beings — the Great Monk harms none of them."},{"id":"sutra-5","num":"22.5","title":"He does not cut, does not break, does not uproot."},{"id":"sutra-6","num":"22.6","title":"Both mobile and stationary beings — the Great Monk protects."},{"id":"sutra-7","num":"22.7","title":"In heat, in cold, in all conditions — he remains equanimous."},{"id":"sutra-8","num":"22.8","title":"He does not become angry; he does not become pleased — equal in all situations."},{"id":"sutra-9","num":"22.9","title":"Dispassionate toward all tastes; not attached."},{"id":"sutra-10","num":"22.10","title":"Not in sounds, not in forms, not in smells —"},{"id":"sutra-11","num":"22.11","title":"Not in touch either — he remains settled there."},{"id":"sutra-12","num":"22.12","title":"The Great Monk has conquered the senses; he has conquered the passions."},{"id":"sutra-13","num":"22.13","title":"Unbroken in his practice of celibacy — the homeless one."},{"id":"sutra-14","num":"22.14","title":"Withdrawn from all means of existence; free of all possessions."},{"id":"sutra-15","num":"22.15","title":"He does not create possessions — knowing what they are."},{"id":"sutra-16","num":"22.16","title":"The Great Monk owns nothing; he has no dwelling."},{"id":"sutra-17","num":"22.17","title":"He lives with the attitude of equanimity in all situations."},{"id":"sutra-18","num":"22.18","title":"Compassionate toward all breathing beings, all organisms, all living beings, all sentient ones."},{"id":"sutra-19","num":"22.19","title":"Not greedy, not deceitful, not of wrong views."},{"id":"sutra-20","num":"22.20","title":"He does not become angry; he does not praise himself; he is equal."},{"id":"sutra-21","num":"22.21","title":"Withdrawn from all evil, freed from all suffering."},{"id":"sutra-22","num":"22.22","title":"He practices intense austerity, going beyond what other teachers require."},{"id":"sutra-23","num":"22.23","title":"He practices begging for alms — according to the proper method."},{"id":"sutra-24","num":"22.24","title":"He neither craves food nor finds fault with it."},{"id":"sutra-25","num":"22.25","title":"He endures disturbances; he is patient."},{"id":"sutra-26","num":"22.26","title":"He does not create hardships for himself — in any situation."},{"id":"sutra-27","num":"22.27","title":"He does not seek out pleasant things; he does not seek out harsh things."},{"id":"sutra-28","num":"22.28","title":"Free of greed, free of delusion, free of passion."},{"id":"sutra-29","num":"22.29","title":"He does not flatter; he does not resent — equal toward all."},{"id":"sutra-30","num":"22.30","title":"As he regards himself, so he regards others."},{"id":"sutra-31","num":"22.31","title":"\"There is no one who is my friend; there is no one who is my enemy.\""},{"id":"sutra-32","num":"22.32","title":"\"All souls are equal\" — in this way he lives."},{"id":"sutra-33","num":"22.33","title":"Withdrawn from all evil, he aspires to liberation."},{"id":"sutra-34","num":"22.34","title":"Wherever the Great Monk goes, there he is luminous."},{"id":"sutra-35","num":"22.35","title":"Seeing him rightly, many have correct faith."},{"id":"sutra-36","num":"22.36","title":"He does not extol himself; he does not disparage others."},{"id":"sutra-37","num":"22.37","title":"Both laypeople and the ordained see him — and are moved."},{"id":"sutra-38","num":"22.38","title":"The qualities of the Jinas, the teaching of the Jinas — following the path, he has seen them."},{"id":"sutra-39","num":"22.39","title":"Going toward the exhaustion of all karma — he is the Great Monk."},{"id":"sutra-40","num":"22.40","title":"One who is beneficial to all beings, equanimous in all situations, withdrawn from all evil — such a one is the Great Monk. — Thus I say."}]},{"file":"sutrakritang-ch23.html","num":"Ch 23","title":"Ch 23 — Nalanada (The Final Teaching)","sutras":[{"id":"hero","num":"Ch 23","title":"Nalanada (The Final Teaching) — The Final Chapter — The Brahmin of Nalanda / Absolute Non-Violence"},{"id":"sutra-1","num":"23.1","title":"In the city of Nalanda, there lived a wise Brahmin."},{"id":"sutra-2","num":"23.2","title":"He came before the Jina to ask about doubts in the teaching."},{"id":"sutra-3","num":"23.3","title":"\"What is the soul? What is the non-soul? What is bondage? What is liberation?\""},{"id":"sutra-4","num":"23.4","title":"\"What is non-violence? What is the teaching? What is restraint?\""},{"id":"sutra-5","num":"23.5","title":"\"What is austerity? What is the path to liberation? How is one freed?\""},{"id":"sutra-6","num":"23.6","title":"\"What is the difference between other teachings and the Jina's teaching?\""},{"id":"sutra-7","num":"23.7","title":"\"I wish to hear, Blessed One — I say this to you.\""},{"id":"sutra-8","num":"23.8","title":"The Blessed Mahavira, having heard and understood —"},{"id":"sutra-9","num":"23.9","title":"Calmly and thoughtfully, Mahavira spoke thus."},{"id":"sutra-10","num":"23.10","title":"\"The soul exists in the world — listen, O Brahmin.\""},{"id":"sutra-11","num":"23.11","title":"The soul is both agent and experiencer — both the individual soul and the highest soul."},{"id":"sutra-12","num":"23.12","title":"The non-soul is all matter, and also the principles of motion and non-motion."},{"id":"sutra-13","num":"23.13","title":"Bondage is the mixing of karma — of the soul with matter."},{"id":"sutra-14","num":"23.14","title":"Liberation is the complete exhaustion of karma — for the soul."},{"id":"sutra-15","num":"23.15","title":"Non-violence is the highest teaching — this is the instruction of the Jinas."},{"id":"sutra-16","num":"23.16","title":"Restraint is the abandoning of the passions — withdrawal from all evil."},{"id":"sutra-17","num":"23.17","title":"Austerity is the exhaustion of karma — completely."},{"id":"sutra-18","num":"23.18","title":"The path to liberation is the three jewels — thus I say."},{"id":"sutra-19","num":"23.19","title":"The difference from other teachings is this —"},{"id":"sutra-20","num":"23.20","title":"That in the Jina's teaching, one works for the benefit of all beings."},{"id":"sutra-21","num":"23.21","title":"Listen, O Brahmin, this is the highest — non-violence is supreme."},{"id":"sutra-22","num":"23.22","title":"All living beings are not to be slain — this is the eternal teaching."},{"id":"sutra-23","num":"23.23","title":"Having heard this, the Brahmin took up the teaching."},{"id":"sutra-24","num":"23.24","title":"All breathing beings, all organisms, all living beings — they are not to be slain."},{"id":"sutra-25","num":"23.25","title":"This indeed has been declared by me, the Blessed One, in the Sutrakritanga: all breathing beings, all beings, all living beings should not be slain."}]}];
  function initSearch() {
    var input = document.getElementById("search-input");
    if (!input) return;
    var wrapper = input.closest(".relative");
    if (!wrapper) return;
    var dropdown = document.getElementById("search-dropdown");
    if (!dropdown) {
      dropdown = document.createElement("div");
      dropdown.id = "search-dropdown";
      wrapper.appendChild(dropdown);
    }
    var currentFile = (location.pathname.split("/").pop() || "").replace(/[?#].*$/, "");
    function highlight(text, query) {
      if (!query) return text;
      return text.replace(new RegExp("(" + query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")", "gi"), "<mark style='background:#fff3c4;color:inherit;border-radius:2px;'>$1</mark>");
    }
    function dispNum(num) { return String(num).replace(/^[A-Za-z]+\s*/, ""); }
    function search(query) {
      if (query.length < 2) { dropdown.style.display = "none"; return; }
      var q = query.toLowerCase();
      var currentMatches = [];
      var otherMatches = [];
      SEARCH_INDEX.forEach(function (chapter) {
        var matches = chapter.sutras.filter(function (s) {
          return s.title.toLowerCase().includes(q) || String(s.num).toLowerCase().includes(q);
        }).slice(0, 5);
        if (!matches.length) return;
        (chapter.file === currentFile ? currentMatches : otherMatches).push({ chapter: chapter, matches: matches });
      });
      var html = "";
      if (currentMatches.length) {
        currentMatches.forEach(function (r) {
          html += "<div class='search-section-label'>" + r.chapter.title + "</div>";
          r.matches.forEach(function (s) {
            html += "<button class='search-result-item' data-local='true' data-id='" + s.id + "'><span class='search-result-num'>" + dispNum(s.num) + "</span><span class='search-result-title'>" + highlight(s.title, query) + "</span></button>";
          });
        });
      }
      if (otherMatches.length) {
        otherMatches.forEach(function (r) {
          html += "<div class='search-section-label'>" + r.chapter.title + "</div>";
          r.matches.forEach(function (s) {
            var link = r.chapter.file + (s.id !== "hero" ? "#" + s.id : "");
            html += "<a class='search-result-item' href='" + link + "'><span class='search-result-num'>" + dispNum(s.num) + "</span><span class='search-result-title'>" + highlight(s.title, query) + "</span></a>";
          });
        });
      }
      if (!html) html = "<div class='search-no-results'>No results for &ldquo;" + query + "&rdquo;</div>";
      dropdown.innerHTML = html;
      dropdown.style.display = "block";
    }
    dropdown.addEventListener("click", function (e) {
      var btn = e.target.closest(".search-result-item[data-local]");
      if (btn) {
        var id = btn.getAttribute("data-id");
        var el = document.getElementById(id);
        if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
        dropdown.style.display = "none";
        input.value = "";
      }
    });
    input.addEventListener("input", function () { search(this.value.trim()); });
    input.addEventListener("keydown", function (e) { if (e.key === "Escape") { dropdown.style.display = "none"; input.value = ""; } });
    document.addEventListener("click", function (e) { if (!wrapper.contains(e.target)) dropdown.style.display = "none"; });
  }
  document.readyState === "loading" ? document.addEventListener("DOMContentLoaded", initSearch) : initSearch();
})();